import{_ as t,o as l,c as a,a0 as r}from"./chunks/framework.jwovEGr5.js";const y=JSON.parse('{"title":"Delete & Restore a Player","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/delete-restore-player.md","filePath":"how-to/delete-restore-player.md"}'),i={name:"how-to/delete-restore-player.md"};function o(s,e,h,n,c,p){return l(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="delete-restore-a-player" tabindex="-1">Delete &amp; Restore a Player <a class="header-anchor" href="#delete-restore-a-player" aria-label="Permalink to &quot;Delete &amp; Restore a Player&quot;">​</a></h1><p>Deleting a player is the heavy option. It removes the player from normal views at the kingdom level. If the person only left an alliance, use <strong>Kick</strong> instead.</p><blockquote><p>Screenshot placeholder: player-delete-impact.png</p></blockquote><h2 id="use-kick-first-when-possible" tabindex="-1">Use kick first when possible <a class="header-anchor" href="#use-kick-first-when-possible" aria-label="Permalink to &quot;Use kick first when possible&quot;">​</a></h2><p>If the player still belongs to the kingdom and only left the alliance, use <a href="./kick-player.html">Kick a Player from the Alliance</a>. That keeps the identity active while removing the current alliance link.</p><h2 id="check-the-impact-before-deleting" tabindex="-1">Check the impact before deleting <a class="header-anchor" href="#check-the-impact-before-deleting" aria-label="Permalink to &quot;Check the impact before deleting&quot;">​</a></h2><p>When you delete from the <strong>Players</strong> page, the app checks whether the player already has important history such as:</p><ul><li>results</li><li>review rows</li><li>nickname history</li><li>membership history</li><li>API sync jobs</li><li>profile-link history</li></ul><p>If that history exists, the app asks for a stronger confirmation with the exact player name.</p><h2 id="delete-the-player" tabindex="-1">Delete the player <a class="header-anchor" href="#delete-the-player" aria-label="Permalink to &quot;Delete the player&quot;">​</a></h2><ol><li>Open <strong>Players</strong>.</li><li>Find the player.</li><li>Use the delete action.</li><li>Confirm the warning.</li></ol><p>After deletion:</p><ul><li>the player is hidden from normal views</li><li>the current alliance link is cleared</li><li>the player can still be restored later</li></ul><h2 id="restore-the-player" tabindex="-1">Restore the player <a class="header-anchor" href="#restore-the-player" aria-label="Permalink to &quot;Restore the player&quot;">​</a></h2><p>If your role can see deleted players directly:</p><ol><li>Turn on <strong>Show deleted</strong> if needed.</li><li>Find the deleted player.</li><li>Select <strong>Restore</strong>.</li></ol><p>Restore may be blocked if another active player now uses the same name in that kingdom.</p><p>If you do not have a direct restore path in the player list, use <a href="./recycle-bin.html">Use the Recycle Bin</a> or ask for a restore through the path your role is allowed to use.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./kick-player.html">Kick a Player from the Alliance</a></li><li><a href="./recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a></li><li><a href="./../reference/alliance-membership.html">How Alliance Membership Works</a></li></ul>',20)])])}const m=t(i,[["render",o]]);export{y as __pageData,m as default};
